import pandas as pd
import matplotlib.pyplot as plt

def task_func(df):
    try:
        if not isinstance(df, pd.DataFrame) or (not df.columns.isin(['Date', 'Sales']).all()):
            raise ValueError("'df' must be a DataFrame with both 'Date' and 'Sales' columns")

        if df.empty:
            raise ValueError("'df' has no data to plot")

        fig, ax = plt.subplots(figsize=(10, 6))
        ax.plot(df['Date'], df['Sales'], marker='', linestyle='-')
        ax.set_xlabel('Date')
        ax.set_ylabel('Sales')
        ax.set_title('Daily Turnover Line Chart')

        return tuple(ax)
    except ValueError as e:
        print(e)
